import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend
} from 'recharts';
import './App.css';

const API_BASE_URL = 'http://127.0.0.1:5000/api';
const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

function App() {
  const [data, setData] = useState(null);
  const [chartData, setChartData] = useState({ trend: [], categories: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Aynı anda iki isteği de atıyoruz
    const fetchAllData = async () => {
      try {
        const [kpiRes, chartRes] = await Promise.all([
          axios.get(`${API_BASE_URL}/kpi/summary`),
          axios.get(`${API_BASE_URL}/charts/data`)
        ]);
        setData(kpiRes.data);
        setChartData(chartRes.data);
        setLoading(false);
      } catch (err) {
        console.error("Veri çekme hatası:", err);
        setLoading(false);
      }
    };

    fetchAllData();
  }, []);

  if (loading) return <div style={{ textAlign: 'center', padding: '50px' }}><h2>📊 InsightFlow Hazırlanıyor...</h2></div>;

  return (
    <div className="App">
      <div className="dashboard-container">
        {/* 1. Başlık Alanı */}
        <header className="header">
          <h1>📊 InsightFlow KDS: E-Ticaret Performans Panosu</h1>
          <p style={{ color: '#666' }}>Canlı Veritabanı Analizi: Aktif ✅</p>
        </header>

        {/* 2. KPI Kartları Alanı */}
        <div className="kpi-cards" style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '30px' }}>
          <div style={cardStyle}>
            <span style={labelStyle}>Toplam Ciro</span>
            <div style={valueStyle}>₺{data?.total_revenue.toLocaleString()}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Dönüşüm Oranı</span>
            <div style={valueStyle}>%{data?.conversion_rate}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Müşteri Sayısı</span>
            <div style={valueStyle}>{data?.unique_customers}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Ort. Sipariş Değeri</span>
            <div style={valueStyle}>₺{data?.aov.toFixed(2)}</div>
          </div>
        </div>

        {/* 3. Grafik Alanı (Canlandı!) */}
        <div className="charts-area" style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '20px' }}>
          {/* Çizgi Grafik - Satış Trendi */}
          <div style={{ ...chartStyle, height: '450px' }}>
            <h3 style={{ marginBottom: '20px' }}>Aylık Gelir Trendi (2024)</h3>
            <ResponsiveContainer width="100%" height="85%">
              <LineChart data={chartData.trend}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis tickFormatter={(value) => `₺${value / 1000}k`} />
                <Tooltip formatter={(value) => `₺${value.toLocaleString()}`} />
                <Line 
                  type="monotone" 
                  dataKey="value" 
                  stroke="#0088FE" 
                  strokeWidth={3} 
                  dot={{ r: 6 }} 
                  activeDot={{ r: 8 }} 
                />
              </LineChart>
            </ResponsiveContainer>
          </div>

          {/* Pasta Grafik - Kategori Dağılımı */}
          <div style={{ ...chartStyle, height: '450px' }}>
            <h3 style={{ marginBottom: '20px' }}>Kategori Dağılımı</h3>
            <ResponsiveContainer width="100%" height="85%">
              <PieChart>
                <Pie
                  data={chartData.categories}
                  cx="50%"
                  cy="45%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                  label
                >
                  {chartData.categories.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" height={36} />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* 4. Detay Tablolar Alanı */}
        <div className="details-area" style={{ marginTop: '30px', padding: '20px', borderTop: '1px solid #ccc', backgroundColor: '#f9f9f9', borderRadius: '8px' }}>
          <h2>Sistem Durumu ve Veri Özeti</h2>
          <p>Veritabanından çekilen toplam sipariş kaydı: <strong>{data?.total_orders.toLocaleString()}</strong></p>
          <p>Son Güncelleme: {new Date().toLocaleTimeString()}</p>
        </div>
      </div>
    </div>
  );
}

// Stil Tanımlamaları
const cardStyle = {
  flex: 1,
  margin: '0 10px',
  padding: '20px',
  backgroundColor: '#ffffff',
  borderRadius: '12px',
  boxShadow: '0 4px 12px rgba(0,0,0,0.08)',
  textAlign: 'center',
  border: '1px solid #eee'
};

const labelStyle = {
  fontSize: '0.85em',
  color: '#888',
  textTransform: 'uppercase',
  display: 'block',
  marginBottom: '8px',
  letterSpacing: '1px'
};

const valueStyle = {
  fontSize: '1.6em',
  fontWeight: 'bold',
  color: '#2c3e50'
};

const chartStyle = {
  backgroundColor: '#ffffff',
  padding: '25px',
  borderRadius: '12px',
  boxShadow: '0 4px 12px rgba(0, 0, 0, 0.08)',
  border: '1px solid #eee'
};

export default App;
